var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【부록-327】 관계자 증언</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35：<color=#ffd34c>【付録-327】 関係者の証言</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【Appendix-327】 Contact Testimony</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【附錄-327】 相關人士證言</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"힐데 소대장님이요?","JPN":"ヒルデ小隊長ですか？","ENG":"Commander Hilde?","TWN":"希爾德小隊長嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"음...... 처음 만났을 때가 제가 고등학교 졸업하고 처음 취업할 때였으니까.......","JPN":"えっと……初めて会ったのは高校卒業後、初めて就職した時だったから……","ENG":"Err... I met her when I got my first job after graduating high school.","TWN":"嗯……我初次見到她，是在高中畢業後第一次就業的時候……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......벌써 시간이 이렇게 지났네요.","JPN":"……もうそんなに経ったんですね。","ENG":"It's already been so long.","TWN":"……已經過這麼久了呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"참 세월 빠르다니까요?","JPN":"本当に、時が経つのは早いものです。","ENG":"Time really flies, huh?","TWN":"真是光陰似箭對吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......특이한 점이요?","JPN":"……変わったところですか？","ENG":"Did I notice anything special about her?","TWN":"……她有什麼特別的地方嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"글쎄요....... 요즘 세상이 워낙 살기 힘들다 보니 성격 괴팍한 거야 별로 특별할 것도 없긴 한데.......","JPN":"さあ……最近は世の中も荒れてるので、偏屈な性格は特異なこととも言えないし……","ENG":"Well... She's always cranky, but that's nothing special in this harsh world.","TWN":"這個嘛……在如今這個生活如此艱難的世界，也難怪性格會變得孤僻……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 그러고 보니 처음에 사장님이 소대장님을 스승님이라고 부르길래 깜짝 놀랐다니까요?","JPN":"あ、そういえば社長が小隊長を師匠と呼ぶのには、本当に驚きましたね。","ENG":"Oh, I was really surprised at first when our CEO called her Master.","TWN":"啊，對了，剛開始聽到老闆叫小隊長「師父」時，嚇了我一跳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그때는 무슨 벌칙 게임 같은 건가 했는데.......","JPN":"初めて見た時は、罰ゲームだと思ったけど……","ENG":"I thought it was some sort of punishment.","TWN":"我還以為是什麼懲罰遊戲呢……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 꼬맹이....... 아니, 소대장님이 그렇게 나이가 많을 줄 누가 알았겠어요?","JPN":"あのチビ……いや、小隊長があんなに年を取ってるとは思いませんでした。","ENG":"Who would have guessed that brat—I mean, commander—was so old?","TWN":"那個矮子……不是，誰能想到小隊長的年紀竟然這麼大呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"한동안 쉬시다가 며칠 전에 복귀하신 것 같은데.......","JPN":"しばらく休んで、数日前に復帰したみたいですけど……","ENG":"She returned a few days ago after taking a long break.","TWN":"好像是休息了一段時間，幾天前才回來……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"역시나 그 어린 모습은 전혀 변함이 없더라고요.","JPN":"やっぱり、あの子供みたいな外見は変わってませんでした。","ENG":"And her appearance hasn't changed at all.","TWN":"果然那個年輕的樣貌完全沒有變化。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"부러워라.......","JPN":"羨ましいな……","ENG":"I'm so jealous of her.","TWN":"好羡慕喔……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"비결이요? 글쎄요....... 역시 화장품 아닐까요?","JPN":"秘訣ですか？　さあ……やっぱり化粧品じゃないですか？","ENG":"Her secret? Well... her cosmetics, I guess?","TWN":"秘訣嗎？嗯……果然是化妝品吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"시윤 군에게 슬쩍 물어 봤는데 이터니움으로 만든 초고가의 특수 안티에이징 크림을 쓴다는 이야기도 있고.......","JPN":"アキヤマ君にこっそり聞いてみたんですが、エタニウム製の超高価な特殊アンチエイジング・クリームを使っているという噂も……","ENG":"I asked Shiyoon once, and he told me that she uses an expensive anti-aging cream made with Eternium.","TWN":"我偷偷問了一下時雲君，好像說是用一種永恆之金製作的超貴特殊抗衰老面霜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하지만 그 ","JPN":"しかし、あの ","ENG":"But it's ","TWN":"但那是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"주. 시. 윤.","JPN":"アキヤマ・シリュウ君","ENG":"Joo. Shi. Yoon.","TWN":"周．時．雲．"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":" 군 말이니까요.","JPN":"の話ですから。","ENG":" we're talking about.","TWN":"君說的話。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"믿을 수가 있어야죠.","JPN":"信じられませんよね。","ENG":"Anything he says is hard to believe.","TWN":"你最好不要相信他。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......본인에게요?","JPN":"……本人にですか？","ENG":"Why don't I ask her directly?","TWN":"……你何不去問本人？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하하, 그건 좀 무서워서...... 그 성격 아시잖아요?","JPN":"はは、それはちょっと怖いので……あの性格、知ってるでしょう？","ENG":"Hah hah, that's a bit scary. You know what she's like.","TWN":"哈哈，這有點可怕耶……您不是很清楚她的個性嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래도 좋은 점도 있어요.","JPN":"でも、いいところもありますよ。","ENG":"But there is a good thing about her.","TWN":"不過也有好處。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"소대장님이 계실 때는 딱히 다른 회사의 텃세 같은 걸 걱정할 필요는 없었으니까요.","JPN":"小隊長がいる時は、他の会社のことを気にする必要がないので。","ENG":"When she was around, none of the other companies dared to mess with us.","TWN":"小隊長在的時候，就不用擔心其他公司欺負我們了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"코핀의 도살마녀라거나, 정신 나간 <color=#ff3636>[CENSORED]</color>, 쌍칼 <color=#ff3636>[CENSORED]</color>가 왔다는 말을 들으면 다들 시비를 걸다가도 조용해지곤 했거든요.","JPN":"コフィンの屠殺魔女だとか、狂気の<color=#ff3636>[CENSORED]</color>、双刀<color=#ff3636>[CENSORED]</color>が来たと聞けば、みんな一瞬で大人しくなるんです。","ENG":"When they heard that Coffin's Slaughtering Witch, Crazy <color=#ff3636>[CENSORED]</color>, or Dual-sword <color=#ff3636>[CENSORED]</color> was coming, they'd all shut their mouths.","TWN":"只要聽到科芬的殺戮魔女， 瘋狂的<color=#ff3636>[CENSORED]</color>、雙刃、<color=#ff3636>[CENSORED]</color>，前來找碴的人都會變得異常安靜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"뭐, 지금은 업계에 괴담처럼 돌아다니는 소문일 뿐이지만요. 하하.","JPN":"まあ、今は業界の怪談みたいになってる噂でしかありませんけど。はは。","ENG":"Well, it's become a rumor in the industry these days. Hah hah.","TWN":"不過，現在也只是個在業界間流傳的怪談而已啦，哈哈。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래도...... 소문만큼 무섭기만 한 분은 아니라고 생각해요.","JPN":"でも……噂のように怖い方ではないと思います。","ENG":"But still... I don't think she's as scary as they say.","TWN":"但就算這樣……但我不覺得她像謠言說的那麼恐怖。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"안 그런 척하지만 자기 소대원들만큼은 확실하게 챙기시거든요.","JPN":"顔には出しませんけど、自分の小隊員はしっかり面倒を見てくれるので。","ENG":"She pretends she doesn't, but she really takes good care of her squad members.","TWN":"雖然裝作沒有的樣子，但她其實是很照顧自己的小隊員。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다이브 작전 중에도 위험한 일이 있으면 항상 솔선해서 앞으로 나서기도 하고.......","JPN":"ダイブ作戦中の危険な状況では、いつも率先して先頭に立つし……","ENG":"If any threat occurs during a Dive mission, she's the first to head out.","TWN":"躍入作戰中要是發生什麼危險，她總是身先士卒衝在最前面。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다들 잘 모르는 사실인데, 힐데 소대장님의 부대는 악명처럼 다치는 사람도 많지만 사망률은 업계 평균을 훨씬 밑돌아요.","JPN":"ヒルデ小隊長の部隊は悪名通りケガ人が多いのですが、死亡率は業界の平均をはるかに下回ります。みんな知らないようですが……","ENG":"And there's one thing that many people are unaware of. Hilde's squad is notorious for high injury rate, but their mortality rate is far below the industry average.","TWN":"有個大家都不知道的事實，即使希爾德小隊長的部隊傷員多得就跟小隊的壞名聲一樣，但死亡率卻遠低於業界平均。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런 걸 보면...... 그냥 감정 표현을 잘 못하시는 분 같기도 해요.","JPN":"それを見ると……うまく感情を表現できないだけなのかな、とも思います。","ENG":"Considering that... I think she just don't know how to express herself.","TWN":"這樣看來……就能知道她只是不擅長表達感情而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"물론 오랜만에 복귀하셨으니까 예전의 명성을 다시 떨치는 모습도 보고 싶긴 하네요, 하하.","JPN":"もちろん久しぶりに復帰したんですから、また昔のように名を馳せる姿も見たいですね。はは。","ENG":"Of course, now that she's back, I would love to see her reclaim her old reputation. Hah hah.","TWN":"當然，她有很久沒回來了，所以我也想看看她重振昔日名聲的樣子呢，哈哈。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어, 어쨌든 소대장님은 우리 회사에 꼭 필요하신 분이라고 생각해요!","JPN":"と、とにかく小隊長はうちの会社に絶対に必要な方だと思います！","ENG":"A-anyway, I think we need her in our company!","TWN":"不管怎樣，我認為小隊長是我們公司不可或缺的人！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아마도!","JPN":"たぶん！","ENG":"Probably!","TWN":"也許！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어......? 잠깐, 잠깐만요!","JPN":"え……？　ちょ、ちょっと待ってください！","ENG":"Huh? Wait, hold on!","TWN":"呃……？等等，等一下！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"손에 그거 좀 보여 주세요!","JPN":"それ見せてください！","ENG":"What's that in your hand?!","TWN":"你手裡拿著的東西讓我看一下！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"지금 녹음하고 있었어요?!","JPN":"録音してたんですか！？","ENG":"Are you recording all this?!","TWN":"你在錄音？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};